import{_ as o}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"ダッシュボード (Dashboard)","description":"","frontmatter":{},"headers":[],"relativePath":"ja/getting-started/dashboard.md","filePath":"ja/getting-started/dashboard.md"}'),s={name:"ja/getting-started/dashboard.md"};function n(l,e,c,d,h,g){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="ダッシュボード-dashboard" tabindex="-1"><i class="ph ph-speedometer"></i> ダッシュボード (Dashboard) <a class="header-anchor" href="#ダッシュボード-dashboard" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; ダッシュボード (Dashboard)&quot;">​</a></h1><p><strong>ダッシュボード</strong>は、強力なゲーム内コントロールパネル兼プロファイラーです。プラグインの動作を監視し、フレームタイミングを分析し、実行中のビルド内でスケーラーレベルを手動で直接オーバーライドすることができます。</p><p><img src="'+o+'" alt=""></p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><p>プロジェクト内の任意のシーンに <code>Dashboard.prefab</code> をドラッグ＆ドロップするだけです。<br> このプレハブは自動的に <code>DontDestroyOnLoad</code> に設定され、シーンの遷移間でもアクティブな状態を維持します。</p><div class="info custom-block"><p class="custom-block-title">プロダクションビルドの注意点</p><p>ダッシュボードはプラグインのコアから完全に分離されています。ゲームをリリースする前に、シーンからこのプレハブを削除するだけで済みます。Unityのコードストリッピング（Code Stripping）システムは、最終ビルドからダッシュボードのすべてのコードを自動的に削除し（<code>Resources</code> フォルダの肥大化を防ぎます）、プロジェクトの容量を最小限に抑えます。WebAPコアは、バックグラウンドで目に見えない形で動作し続けます。</p></div><h2 id="左パネル-コントロール" tabindex="-1"><i class="ph ph-sliders"></i> 左パネル（コントロール） <a class="header-anchor" href="#左パネル-コントロール" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; 左パネル（コントロール）&quot;">​</a></h2><p>ダッシュボードの左側は、プラグインとリアルタイムで対話するために設計されています。</p><ul><li><strong>Enable Web AP</strong><br> プラグインコアのメインスイッチです。無効にすると、自動最適化が停止し、すべてのグラフィックパラメータが元の（最大）値に戻ります。</li><li><strong>Anti Yo-Yo Protection</strong><br> ペナルティロックアウト（Penalty Lockout）をオンまたはオフにします。無効にすると、プラグインはタイムロックなしで継続的にグラフィック品質を上げ下げできます。<br><em>（詳細：<a href="./../advanced/anti-yoyo">アンチヨーヨーシステム</a>）</em></li><li><strong>Active Scalers</strong><br> システムに追加されたすべての最適化モジュールのリストです。 <ul><li><strong>Toggle（トグル）：</strong> 特定のスケーラーを動的に完全に有効または無効にします。</li><li><strong>Slider（スライダー）：</strong> 品質レベルを手動でオーバーライド（<code>Override Level</code>）します。<code>0</code> は最大品質を意味します。スライダーを動かすと、インデクサー（Indexer）はこのスケーラーの管理を停止し、ゲームへの影響を視覚的に評価できるようになります。</li><li><strong>Resolution Mode（解像度モード）：</strong> <code>Resolution Scaler</code> 専用の設定です（BiRPモード）。<code>NativeBrowserScaling</code> 戦略と <code>RenderTextureScaling</code> 戦略を動的に切り替えることができます。<br><em>（詳細：<a href="./../scalers/reference">スケーラーリファレンス</a>）</em></li></ul></li></ul><h2 id="右パネル-分析" tabindex="-1"><i class="ph ph-chart-bar"></i> 右パネル（分析） <a class="header-anchor" href="#右パネル-分析" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; 右パネル（分析）&quot;">​</a></h2><p>右側は、エンジンの生メトリクスとプラグインの「頭脳」の内部ロジックを表示します。チャートを滑らかにするために、Zero-GCの指数移動平均（Exponential Moving Average）アルゴリズムが使用されています。</p><h3 id="メトリクスとタイミング-metrics-timings" tabindex="-1">メトリクスとタイミング (Metrics &amp; Timings) <a class="header-anchor" href="#メトリクスとタイミング-metrics-timings" aria-label="Permalink to &quot;メトリクスとタイミング (Metrics &amp; Timings)&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> プロジェクト設定から取得されたベースラインのパフォーマンス目標。</li><li><strong>Current FPS:</strong> 現在のフレームレートとスパイク履歴のグラフ。</li><li><strong>Current Scale / DPI:</strong> 現在の解像度の乗数。<code>1.00</code> はネイティブ解像度を表します。低い値（例：<code>0.50</code>）は、GPUを節約するために3Dワールドがダウンスケールされていることを示します。</li><li><strong>Frame Time / CPU Time:</strong> <code>FrameTimingManager</code> を介して収集されたハードウェアの正確な時間。プロセッサがフレームのロジックに実際にどれだけの時間を費やしているかを理解するのに役立ちます。</li></ul><h3 id="プラグインの頭脳-plugin-brain" tabindex="-1">プラグインの頭脳 (Plugin Brain) <a class="header-anchor" href="#プラグインの頭脳-plugin-brain" aria-label="Permalink to &quot;プラグインの頭脳 (Plugin Brain)&quot;">​</a></h3><p>決定パイプラインのロジックを表示します。<br><em>（詳細：<a href="./../advanced/how-it-works">仕組み</a>）</em></p><ul><li><strong>Bottleneck:</strong> デバイスのどのサブシステムが現在遅延を引き起こしているかを特定します（<code>CPU</code>、<code>GPU</code>、<code>TargetFrameRate</code>、または <code>Unknown</code>）。</li><li><strong>Action:</strong> インデクサーが何をしようとしているかを示します（<code>IncreaseQuality</code>、<code>DecreaseQuality</code>、または <code>Stale</code> — 何もする必要がない場合）。</li><li><strong>Status (Actionの下):</strong> システムの状態：<code>Monitoring...</code>（フレームの評価中）、<code>Cooldown</code>（グラフィック変更後の安定化待ち）、または <code>Penalty Lockout</code>（アンチヨーヨーペナルティがアクティブ）。</li></ul><h3 id="アクティブ-active" tabindex="-1">アクティブ (Active) <a class="header-anchor" href="#アクティブ-active" aria-label="Permalink to &quot;アクティブ (Active)&quot;">​</a></h3><ul><li>パフォーマンスを維持するために、システムによって現在レベルが<strong>下げられている</strong>スケーラーのリスト。FPSが高く、すべてが最適化されている場合は、<code>- None</code> と表示されます。</li></ul>',18)])])}const b=a(s,[["render",n]]);export{m as __pageData,b as default};
